1	const PROCESSING_FEE = 5;
2	const INITIAL_ASSESSMENT_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	};
10	type QuoteResult = { premium: number };
11	type ScenarioResult = { results: QuoteResult[] };
12	
13	const BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const sumBasePremiums = (items: Item[]): number =>
23	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
24	
25	const quotePremium = (step: QuoteStep): number => {
26	  const base = sumBasePremiums(step.items);
27	  const surcharge = base * INITIAL_ASSESSMENT_SURCHARGE_RATE;
28	  return Math.ceil(base + surcharge) + PROCESSING_FEE;
29	};
30	
31	export const runScenario = (input: Scenario): ScenarioResult => {
32	  const results = input.steps.map((step) => ({ premium: quotePremium(step) }));
33	  return { results };
34	};
